142→    fun downloadPdf(url: String, smsId: Long, fileName: String? = null, cookies: String? = null) {
143→        viewModelScope.launch {
144→            val result = pdfDownloader.download(url, smsId, fileName, cookies)
145→            when (result) {
146→                is DownloadResult.Success -> {
147→                    val pdf = PdfDocumentEntity(
148→                        smsId = smsId,
149→                        fileName = result.fileName,
150→                        filePath = result.filePath,
151→                        fileSize = result.fileSize,
152→                        fileMd5 = result.fileMd5,
153→                        downloadedAt = System.currentTimeMillis(),
154→                        isSubpoena = false
155→                    )
156→                    // 唯一索引(smsId, fileMd5)保证同一短信下不重复
157→                    val pdfId = repo.insertPdf(pdf)
158→                    if (pdfId > 0) {
159→                        _uiState.update { it.copy(downloadCount = it.downloadCount + 1) }
160→                        _downloadEvent.emit("已保存: ${result.fileName}")
161→                        tryParseAndSync(pdfId, result.filePath, smsId)
162→                        refreshPdfList()
163→                    } else {
164→                        File(result.filePath).delete()
165→                        _downloadEvent.emit("文件已存在: ${result.fileName}")
166→                    }
167→                }
168→                is DownloadResult.Error -> {
169→                    _downloadEvent.emit("下载失败: ${result.message}")
170→                }
171→            }
172→        }
173→    }
174→
175→    private suspend fun tryParseAndSync(pdfId: Long, filePath: String, smsId: Long) {
176→        val info = pdfParser.parseSubpoena(filePath) ?: return
177→        val pdf = repo.getPdfById(pdfId) ?: return
178→
179→        // 判断是否为传票：有开庭时间或文件名/内容含传票关键词
180→        val isSubpoena = info.hearingTime != null ||
181→            pdf.fileName.contains("传票") ||
182→            info.defendant != null
183→
184→        val hearingDesc = buildString {
185→            if (info.courtName != null) append("法院: ${info.courtName}\n")
186→            if (info.defendant != null) append("被传唤人: ${info.defendant}\n")
187→            if (info.handler != null) append("承办人: ${info.handler}\n")
188→            if (info.location != null) append("地点: ${info.location}")
189→            if (info.phone != null) append("\n电话: ${info.phone}")
190→        }.takeIf { it.isNotBlank() }
191→
192→        if (info.hearingTime != null && info.caseNumber != null) {
193→            val eventId = calendarSync.syncHearing(
194→                caseNumber = info.caseNumber,
195→                courtName = info.courtName,
196→                hearingTime = info.hearingTime,
197→                defendant = info.defendant,
198→                handler = info.handler,
199→                location = info.location,
200→                phone = info.phone,
201→                caseType = info.caseType
202→            )
203→            repo.updatePdf(pdf.copy(isSubpoena = isSubpoena, hearingInfo = hearingDesc, calendarEventId = eventId))
204→            if (eventId != null) {
205→                _downloadEvent.emit("📅 已同步到日历")
206→            }
207→        } else if (hearingDesc != null || isSubpoena) {
208→            repo.updatePdf(pdf.copy(isSubpoena = isSubpoena, hearingInfo = hearingDesc))
209→        }
210→    }
211→
212→    fun resetDownloadCount() {
213→        _uiState.update { it.copy(downloadCount = 0) }
214→    }
215→
216→    fun clearMessage() {
217→        _uiState.update { it.copy(message = null) }
218→    }
