227→    fun syncAllToCalendar() {
228→        viewModelScope.launch {
229→            _uiState.update { it.copy(loading = true) }
230→            var synced = 0
231→            // 同步短信中的开庭信息
232→            resyncPendingSms()
233→            // 同步所有PDF
234→            val allPdfs = repo.getAllPdfs().first()
235→            for (pdf in allPdfs) {
236→                if (pdf.calendarEventId != null) continue
237→                val info = pdfParser.parseSubpoena(pdf.filePath) ?: continue
238→                if (info.hearingTime == null || info.caseNumber == null) continue
239→                val eventId = calendarSync.syncHearing(
240→                    caseNumber = info.caseNumber,
241→                    courtName = info.courtName,
242→                    hearingTime = info.hearingTime,
243→                    defendant = info.defendant,
244→                    handler = info.handler,
245→                    location = info.location,
246→                    phone = info.phone,
247→                    caseType = info.caseType
248→                ) ?: continue
249→                val hearingDesc = buildString {
250→                    if (info.courtName != null) append("法院: ${info.courtName}\n")
251→                    if (info.defendant != null) append("被传唤人: ${info.defendant}\n")
252→                    if (info.handler != null) append("承办人: ${info.handler}\n")
253→                    if (info.location != null) append("地点: ${info.location}")
254→                    if (info.phone != null) append("\n电话: ${info.phone}")
255→                }.takeIf { it.isNotBlank() }
256→                repo.updatePdf(pdf.copy(isSubpoena = true, hearingInfo = hearingDesc, calendarEventId = eventId))
257→                synced++
258→            }
259→            _uiState.update { it.copy(loading = false, message = if (synced > 0) "已同步 $synced 条日程" else "没有新的日程需要同步") }
260→        }
261→    }
